import type { Route } from "next";
import Link from "next/link";

import {
  Button,
  DetailBlock,
  FormField,
  IntroBlock,
  MetadataRow,
  SectionHeading,
  Surface,
  TagChip,
  TagList
} from "@/components/ui/primitives";
import { EnrichmentPendingRefresh } from "@/features/enrichment/components/pending-refresh";
import { EnrichmentStatusBlock } from "@/features/enrichment/components/status-block";
import { LinkFavicon } from "@/features/links/components/link-favicon";
import { OwnerNoteCard } from "@/features/notes/components/owner-note-card";
import { searchOwnerContent } from "@/features/search/service";
import { requireOwnerSession } from "@/lib/auth/owner-session";

type SearchPageProps = {
  searchParams?: Promise<{
    q?: string;
  }>;
};

export default async function SearchPage({ searchParams }: SearchPageProps) {
  const owner = await requireOwnerSession();
  const resolvedSearchParams = (await searchParams) ?? {};
  const results = await searchOwnerContent(owner.id, resolvedSearchParams.q);
  const resultCount = results.notes.length + results.links.length;
  const dateFormatter = new Intl.DateTimeFormat("en", { dateStyle: "medium" });
  const hasPendingResults =
    results.notes.some((note) => note.enrichment.status === "pending") ||
    results.links.some((link) => link.enrichment.status === "pending");

  return (
    <div className="feature-layout">
      <EnrichmentPendingRefresh enabled={hasPendingResults} />
      <Surface className="secondary-route-hero" density="compact" tone="hero">
        <IntroBlock
          compact
          description="This search stays inside the owner area. Public readers do not get a search interface in v1."
          eyebrow="Owner search"
          title="Search the private vault"
        >
          <div aria-label="Search overview" className="ui-support-grid secondary-summary-grid">
            <DetailBlock title="Scope">
              <p>Titles, URLs, and shared tag names.</p>
            </DetailBlock>
            <DetailBlock title="Body search">
              <p>Note bodies and link summaries stay out of scope in v1.</p>
            </DetailBlock>
            <DetailBlock title="Current results">
              <p>{results.query ? `${resultCount} match${resultCount === 1 ? "" : "es"}` : "Run a query to inspect the vault."}</p>
            </DetailBlock>
          </div>
        </IntroBlock>
      </Surface>

      <Surface
        action="/app/search"
        as="form"
        className="search-form secondary-search-form"
        density="compact"
        role="search"
        tone="panel"
      >
        <SectionHeading meta="Owner-only retrieval" title="Query" />
        <div className="secondary-search-controls">
          <FormField className="secondary-search-field" label="Query">
            <input
              autoComplete="off"
              className="text-input"
              defaultValue={results.query}
              name="q"
              placeholder="Search note titles, link titles, URLs, or tags"
              type="search"
            />
          </FormField>
          <div className="button-row secondary-search-actions">
            <Button type="submit">Search</Button>
          </div>
        </div>
      </Surface>

      {results.query ? (
        <div className="retrieval-grid secondary-retrieval-grid">
          <Surface className="secondary-list-panel secondary-note-panel" density="compact" tone="panel">
            <SectionHeading meta={`${results.notes.length} result${results.notes.length === 1 ? "" : "s"}`} title="Matching notes" />
            {results.notes.length === 0 ? (
              <p>No private notes matched this query.</p>
            ) : (
              <div className="note-list">
                {results.notes.map((note) => (
                  <OwnerNoteCard
                    href={`/app/notes/${note.id}/edit` as Route}
                    key={note.id}
                    note={note}
                    secondary
                    updatedAtLabel={dateFormatter.format(note.updatedAt)}
                  />
                ))}
              </div>
            )}
          </Surface>

          <Surface className="secondary-list-panel secondary-link-panel" density="compact" tone="panel">
            <SectionHeading meta={`${results.links.length} result${results.links.length === 1 ? "" : "s"}`} title="Matching links" />
            {results.links.length === 0 ? (
              <p>No private links matched this query.</p>
            ) : (
              <div className="link-list">
                {results.links.map((link) => (
                  <article className="link-list-item secondary-link-item" key={link.id}>
                    <div className="secondary-link-main">
                      <div className="link-list-heading secondary-link-heading">
                        <LinkFavicon
                          faviconAssetId={link.faviconAssetId}
                          frameClassName="link-favicon-frame secondary-link-favicon-frame"
                          imageClassName="link-favicon-image secondary-link-favicon-image"
                        />
                        <div className="secondary-link-heading-copy">
                          <MetadataRow leading>
                            <span>Private link</span>
                            <span>{dateFormatter.format(link.updatedAt)}</span>
                          </MetadataRow>
                          <a className="note-list-link" href={link.url} rel="noopener noreferrer" target="_blank">
                            {link.title}
                          </a>
                          <p className="link-url">{link.url}</p>
                        </div>
                      </div>
                      <div className="link-list-footer secondary-link-footer">
                        <MetadataRow>
                          <span>Query</span>
                          <span>{results.query}</span>
                        </MetadataRow>
                      </div>
                    </div>
                    <div className="secondary-link-meta">
                      <EnrichmentStatusBlock detailClassName="secondary-link-status" state={link.enrichment} />
                      <div className="note-generated-copy secondary-generated-copy">
                        <strong>AI summary:</strong>
                        {link.summary ? (
                          <p className="link-summary">{link.summary}</p>
                        ) : (
                          <p className="field-note">A generated summary will appear here after a successful enrichment run.</p>
                        )}
                      </div>
                      <div className="note-generated-copy secondary-generated-copy">
                        <strong>AI tags</strong>
                        <TagList aria-label="Link tags">
                          {link.tags.length === 0 ? (
                            <TagChip muted>No generated tags yet</TagChip>
                          ) : (
                            link.tags.map((tag) => (
                              <TagChip key={tag.id}>
                                {tag.name}
                              </TagChip>
                            ))
                          )}
                        </TagList>
                      </div>
                    </div>
                  </article>
                ))}
              </div>
            )}
          </Surface>
        </div>
      ) : (
        <Surface className="secondary-list-panel" density="compact" tone="panel">
          <SectionHeading meta="v1 boundaries" title="Search scope" />
          <p>Search matches note titles, link titles, link URLs, and shared tag names. Note bodies and link summaries stay out of scope in v1.</p>
        </Surface>
      )}
    </div>
  );
}

import type { Route } from "next";
import Link from "next/link";

import { DetailBlock, IntroBlock, MetadataRow, SectionHeading, Surface, TagChip, TagList } from "@/components/ui/primitives";
import { EnrichmentPendingRefresh } from "@/features/enrichment/components/pending-refresh";
import { EnrichmentStatusBlock } from "@/features/enrichment/components/status-block";
import { LinkFavicon } from "@/features/links/components/link-favicon";
import { OwnerNoteCard } from "@/features/notes/components/owner-note-card";
import { listOwnerTags, listOwnerContentByTag } from "@/features/tags/service";
import { normalizeSingleTagName } from "@/features/tags/normalize";
import { requireOwnerSession } from "@/lib/auth/owner-session";

type TagsPageProps = {
  searchParams?: Promise<{
    tag?: string;
  }>;
};

export default async function TagsPage({ searchParams }: TagsPageProps) {
  const owner = await requireOwnerSession();
  const resolvedSearchParams = (await searchParams) ?? {};
  const selectedTag = normalizeSingleTagName(resolvedSearchParams.tag);
  const dateFormatter = new Intl.DateTimeFormat("en", { dateStyle: "medium" });
  const [tags, filteredContent] = await Promise.all([
    listOwnerTags(owner.id),
    listOwnerContentByTag(owner.id, selectedTag)
  ]);
  const hasPendingResults =
    filteredContent.notes.some((note) => note.enrichment.status === "pending") ||
    filteredContent.links.some((link) => link.enrichment.status === "pending");

  return (
    <div className="feature-layout">
      <EnrichmentPendingRefresh enabled={hasPendingResults} />
      <Surface className="secondary-route-hero" density="compact" tone="hero">
        <IntroBlock
          compact
          description="Shared tags stay owner-only in v1. Pick a tag to narrow private notes and saved links without exposing retrieval on the public site."
          eyebrow="Shared tags"
          title="Browse one private taxonomy"
        >
          <div aria-label="Tags overview" className="ui-support-grid secondary-summary-grid">
            <DetailBlock title="Tag library">
              <p>{tags.length} shared tag{tags.length === 1 ? "" : "s"}</p>
            </DetailBlock>
            <DetailBlock title="Selection">
              <p>{selectedTag ?? "All private content"}</p>
            </DetailBlock>
            <DetailBlock title="Boundary">
              <p>Tag exploration stays inside the owner area.</p>
            </DetailBlock>
          </div>
        </IntroBlock>
      </Surface>

      <Surface className="secondary-filter-panel" density="compact" tone="panel">
        <SectionHeading meta="Shared across notes and links" title="Tag filters" />
        <div className="tag-filter-list secondary-tag-filters" aria-label="Shared tag filters">
          <Link
            className={!selectedTag ? "tag-filter-link tag-filter-link-active secondary-tag-filter" : "tag-filter-link secondary-tag-filter"}
            href="/app/tags"
          >
            All content
          </Link>
          {tags.length === 0 ? (
            <TagChip muted>No shared tags yet</TagChip>
          ) : (
            tags.map((tag) => (
              <Link
                className={
                  selectedTag === tag.name
                    ? "tag-filter-link tag-filter-link-active secondary-tag-filter"
                    : "tag-filter-link secondary-tag-filter"
                }
                href={`/app/tags?tag=${encodeURIComponent(tag.name)}`}
                key={tag.id}
              >
                {tag.name}
                <span className="tag-filter-count">
                  {tag.noteCount} note{tag.noteCount === 1 ? "" : "s"} / {tag.linkCount} link{tag.linkCount === 1 ? "" : "s"}
                </span>
              </Link>
            ))
          )}
        </div>
      </Surface>

      <div className="retrieval-grid secondary-retrieval-grid">
        <Surface className="secondary-list-panel secondary-note-panel" density="compact" tone="panel">
          <SectionHeading meta={`${filteredContent.notes.length} note${filteredContent.notes.length === 1 ? "" : "s"}`} title={selectedTag ? `Notes tagged ${selectedTag}` : "Private notes"} />
          {filteredContent.notes.length === 0 ? (
            <p>{selectedTag ? "No private notes match this tag yet." : "No private notes yet."}</p>
          ) : (
            <div className="note-list">
              {filteredContent.notes.map((note) => (
                <OwnerNoteCard
                  href={`/app/notes/${note.id}/edit` as Route}
                  key={note.id}
                  note={note}
                  secondary
                  updatedAtLabel={dateFormatter.format(note.updatedAt)}
                />
              ))}
            </div>
          )}
        </Surface>

        <Surface className="secondary-list-panel secondary-link-panel" density="compact" tone="panel">
          <SectionHeading meta={`${filteredContent.links.length} link${filteredContent.links.length === 1 ? "" : "s"}`} title={selectedTag ? `Links tagged ${selectedTag}` : "Private links"} />
          {filteredContent.links.length === 0 ? (
            <p>{selectedTag ? "No private links match this tag yet." : "No private links yet."}</p>
          ) : (
            <div className="link-list">
              {filteredContent.links.map((link) => (
                <article className="link-list-item secondary-link-item" key={link.id}>
                  <div className="secondary-link-main">
                    <div className="link-list-heading secondary-link-heading">
                      <LinkFavicon
                        faviconAssetId={link.faviconAssetId}
                        frameClassName="link-favicon-frame secondary-link-favicon-frame"
                        imageClassName="link-favicon-image secondary-link-favicon-image"
                      />
                      <div className="secondary-link-heading-copy">
                        <MetadataRow leading>
                          <span>Private link</span>
                          <span>{dateFormatter.format(link.updatedAt)}</span>
                        </MetadataRow>
                        <a className="note-list-link" href={link.url} rel="noopener noreferrer" target="_blank">
                          {link.title}
                        </a>
                        <p className="link-url">{link.url}</p>
                      </div>
                    </div>
                    <div className="link-list-footer secondary-link-footer">
                      <MetadataRow>
                        <span>Selection</span>
                        <span>{selectedTag ?? "All tags"}</span>
                      </MetadataRow>
                    </div>
                  </div>
                  <div className="secondary-link-meta">
                    <EnrichmentStatusBlock detailClassName="secondary-link-status" state={link.enrichment} />
                    <div className="note-generated-copy secondary-generated-copy">
                      <strong>AI summary:</strong>
                      {link.summary ? (
                        <p className="link-summary">{link.summary}</p>
                      ) : (
                        <p className="field-note">A generated summary will appear here after a successful enrichment run.</p>
                      )}
                    </div>
                    <div className="note-generated-copy secondary-generated-copy">
                      <strong>AI tags</strong>
                      <TagList aria-label="Link tags">
                        {link.tags.length === 0 ? (
                          <TagChip muted>No generated tags yet</TagChip>
                        ) : (
                          link.tags.map((tag) => (
                            <TagChip key={tag.id}>
                              {tag.name}
                            </TagChip>
                          ))
                        )}
                      </TagList>
                    </div>
                  </div>
                </article>
              ))}
            </div>
          )}
        </Surface>
      </div>
    </div>
  );
}

import {
  createLinkAction,
  publishLinkAction,
  refreshLinkFaviconAction,
  retryLinkEnrichmentAction,
  unpublishLinkAction
} from "@/app/app/links/actions";
import {
  Button,
  DetailBlock,
  FormField,
  IntroBlock,
  MetadataRow,
  SectionHeading,
  Surface,
  TagChip,
  TagList
} from "@/components/ui/primitives";
import { EnrichmentPendingRefresh } from "@/features/enrichment/components/pending-refresh";
import { EnrichmentStatusBlock } from "@/features/enrichment/components/status-block";
import { LinkFavicon } from "@/features/links/components/link-favicon";
import { listOwnerLinks } from "@/features/links/service";
import { requireOwnerSession } from "@/lib/auth/owner-session";

type LinksPageProps = {
  searchParams?: Promise<{
    saved?: string;
    retried?: string;
    published?: string;
    unpublished?: string;
    favicon?: string;
    error?: string;
  }>;
};

function getStatusMessage(error?: string) {
  switch (error) {
    case "duplicate-url":
      return "That URL is already saved in your private links.";
    case "invalid-url":
      return "Enter a complete http:// or https:// URL.";
    case "missing-title":
      return "Enter a title for the saved link.";
    default:
      return undefined;
  }
}

export default async function LinksPage({ searchParams }: LinksPageProps) {
  const owner = await requireOwnerSession();
  const resolvedSearchParams = (await searchParams) ?? {};
  const links = await listOwnerLinks(owner.id);
  const pendingLinks = links.filter((link) => link.enrichment.status === "pending").length;
  const publishedLinks = links.filter((link) => link.isPublished).length;
  const dateFormatter = new Intl.DateTimeFormat("en", { dateStyle: "medium" });
  const statusMessage =
    resolvedSearchParams.saved === "1"
      ? "Link saved."
      : resolvedSearchParams.retried === "1"
        ? "Retry requested."
        : resolvedSearchParams.published === "1"
          ? "Link published."
          : resolvedSearchParams.unpublished === "1"
            ? "Link unpublished."
            : resolvedSearchParams.favicon === "1"
              ? "Favicon refresh requested."
              : getStatusMessage(resolvedSearchParams.error);

  return (
    <div className="feature-layout">
      <EnrichmentPendingRefresh enabled={links.some((link) => link.enrichment.status === "pending")} />
      <Surface className="secondary-route-hero" density="compact" tone="hero">
        <IntroBlock
          compact
          description="Save the URL and title first, then let Minakeep generate the AI summary and shared tags. Links stay private until the owner explicitly publishes them to the public showroom."
          eyebrow="Private links"
          title="Reference shelf"
        >
          <div aria-label="Links overview" className="ui-support-grid secondary-summary-grid">
            <DetailBlock title="Saved links">
              <p>{links.length} private reference{links.length === 1 ? "" : "s"}</p>
            </DetailBlock>
            <DetailBlock title="AI queue">
              <p>{pendingLinks === 0 ? "No pending enrichment" : `${pendingLinks} link${pendingLinks === 1 ? "" : "s"} pending`}</p>
            </DetailBlock>
            <DetailBlock title="Visibility">
              <p>
                {publishedLinks === 0
                  ? "All links are private until explicitly published."
                  : `${publishedLinks} link${publishedLinks === 1 ? "" : "s"} visible on the public showroom.`}
              </p>
            </DetailBlock>
          </div>
        </IntroBlock>
        {statusMessage ? (
          <p className={resolvedSearchParams.error ? "status-note status-note-error" : "status-note"}>{statusMessage}</p>
        ) : null}
      </Surface>

      <div className="link-manager-grid secondary-route-grid">
        <Surface action={createLinkAction} as="form" className="link-form secondary-control-panel" density="compact" tone="panel">
          <SectionHeading meta="Manual URL and title" title="Capture" />
          <FormField label="URL">
            <input
              autoComplete="url"
              className="text-input"
              name="url"
              placeholder="https://example.com/article"
              required
              type="url"
            />
          </FormField>
          <FormField label="Title">
            <input
              autoComplete="off"
              className="text-input"
              name="title"
              placeholder="Reference title"
              required
              type="text"
            />
          </FormField>
          <p className="field-note">AI summary and shared tags are generated automatically after save.</p>
          <div className="button-row">
            <Button type="submit">Save link</Button>
          </div>
        </Surface>

        <Surface className="link-list-panel secondary-list-panel secondary-link-panel" density="compact" tone="panel">
          <SectionHeading meta={`${links.length} saved`} title="Saved links" />
          {links.length === 0 ? (
            <p>No saved links yet. Capture the first private bookmark from this page.</p>
          ) : (
            <div className="link-list">
              {links.map((link) => (
                <article className="link-list-item secondary-link-item" key={link.id}>
                  <div className="secondary-link-main">
                    <div className="link-list-heading secondary-link-heading">
                      <div className="secondary-link-favicon-stack">
                        <LinkFavicon
                          faviconAssetId={link.faviconAssetId}
                          frameClassName="link-favicon-frame secondary-link-favicon-frame"
                          imageClassName="link-favicon-image secondary-link-favicon-image"
                          testId="owner-link-favicon"
                        />
                        <form action={refreshLinkFaviconAction.bind(null, link.id)} className="secondary-link-favicon-refresh">
                          <Button aria-label="Refresh favicon" title="Refresh favicon" type="submit" variant="ghost">
                            ↻
                          </Button>
                        </form>
                      </div>
                      <div className="secondary-link-heading-copy">
                        <MetadataRow leading>
                          <span>{link.isPublished ? "Published link" : "Private link"}</span>
                          <span>{dateFormatter.format(link.isPublished && link.publishedAt ? link.publishedAt : link.updatedAt)}</span>
                        </MetadataRow>
                        <a className="note-list-link" href={link.url} rel="noopener noreferrer" target="_blank">
                          {link.title}
                        </a>
                        <p className="link-url">{link.url}</p>
                      </div>
                    </div>
                    <div className="link-list-footer secondary-link-footer">
                      <MetadataRow>
                        <span>Visibility</span>
                        <span>{link.isPublished ? "Public showroom" : "Owner only"}</span>
                      </MetadataRow>
                    </div>
                  </div>
                  <div className="secondary-link-meta">
                    <EnrichmentStatusBlock detailClassName="secondary-link-status" state={link.enrichment} />
                    <div className="note-generated-copy secondary-generated-copy">
                      <strong>AI summary:</strong>
                      {link.summary ? (
                        <p className="link-summary" data-testid="link-ai-summary">
                          {link.summary}
                        </p>
                      ) : (
                        <p className="field-note">A generated summary will appear here after a successful enrichment run.</p>
                      )}
                    </div>
                    <div className="note-generated-copy secondary-generated-copy">
                      <strong>AI tags</strong>
                      <TagList aria-label="Link tags" data-testid="link-ai-tags">
                        {link.tags.length === 0 ? (
                          <TagChip muted>No generated tags yet</TagChip>
                        ) : (
                          link.tags.map((tag) => (
                            <TagChip key={tag.id}>
                              {tag.name}
                            </TagChip>
                          ))
                        )}
                      </TagList>
                    </div>
                  </div>
                  <div className="button-row secondary-link-actions">
                    {link.isPublished ? (
                      <form action={unpublishLinkAction.bind(null, link.id)}>
                        <Button type="submit" variant="ghost">
                          Unpublish link
                        </Button>
                      </form>
                    ) : (
                      <form action={publishLinkAction.bind(null, link.id)}>
                        <Button type="submit">Publish link</Button>
                      </form>
                    )}
                  </div>
                  {link.enrichment.status === "failed" ? (
                    <form action={retryLinkEnrichmentAction.bind(null, link.id)} className="secondary-link-retry">
                      <Button type="submit" variant="ghost">
                        Retry AI enrichment
                      </Button>
                    </form>
                  ) : null}
                </article>
              ))}
            </div>
          )}
        </Surface>
      </div>
    </div>
  );
}

