}

.section-heading,
.ui-section-heading {
  align-items: baseline;
  border-bottom: 1px solid var(--line);
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem 0.75rem;
  justify-content: space-between;
  margin-bottom: 0.15rem;
  padding-bottom: var(--space-4);
}

.section-meta {
  font-family: var(--font-ui);
  font-size: var(--text-xs);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.detail-stack {
  margin-top: var(--space-4);
}

.ui-support-grid {
  gap: 0.75rem;
}

.ui-support-grid-dual {
  grid-template-columns: minmax(0, 1fr);
}

.ui-support-grid-balanced {
  grid-template-columns: minmax(0, 1fr);
}

.ui-support-grid .ui-detail-block,
.ui-support-grid .detail-block {
  padding: 0.8rem 0.85rem;
}

.ui-support-grid .ui-detail-block strong,
.ui-support-grid .detail-block strong {
  margin-bottom: 0.3rem;
}

.ui-form-stack {
  gap: 0.85rem;
}

.vault-shell {
  width: 100%;
}

.vault-frame {
  box-shadow: var(--shadow-soft);
  display: grid;
  gap: 0;
  padding: var(--space-4);
}

.vault-shell-grid {
  align-items: start;
  display: grid;
  gap: var(--space-5);
  min-width: 0;
}

.vault-frame-header {
  border-bottom: 1px solid var(--line);
  display: grid;
  gap: var(--space-4);
  padding-bottom: var(--space-4);
}

.vault-nav-block {
  gap: var(--space-3);
}

.vault-nav-label {
  color: var(--ink-faint);
  font-family: var(--font-ui);
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.16em;
  margin: 0;
  text-transform: uppercase;
}

.vault-nav {
  gap: 0.55rem;
}

.vault-frame-body {
  display: grid;
  gap: var(--space-5);
  min-width: 0;
}

.vault-frame-body > * {
  min-width: 0;
}

.public-home-layout,
.public-note-layout,
.login-layout {
  align-items: start;
}

.dashboard-hero,
.dashboard-hero-head,
.dashboard-hero-copy,
.dashboard-stat,
.dashboard-note-primary,
.dashboard-note-secondary,
.dashboard-note-ai,
.dashboard-route-grid {
  display: grid;
}

.public-home-layout {
  gap: var(--public-shell-gap);
}

.public-home-layout > *,
.public-home-archive-head > *,
.public-home-shell-head > *,
.public-search-controls > * {
  min-width: 0;
}

.public-note-layout {
  gap: var(--public-shell-gap);
}

.dashboard-hero {
  gap: var(--space-3);
  overflow: hidden;
  padding: 0.9rem 1rem;
}

.dashboard-hero-head {
  gap: 0.75rem;
}

.dashboard-hero-copy {
  gap: var(--space-2);
}

.dashboard-hero .dashboard-hero-title {
  font-size: clamp(1.42rem, 2.45vw, 1.92rem);
  line-height: 1.02;
  letter-spacing: -0.035em;
  margin: 0;
  max-width: 14ch;
}

.dashboard-hero-lede {
  font-size: var(--text-sm);
  line-height: 1.55;
  max-width: 35rem;
}

.dashboard-hero-actions {
  align-content: start;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  margin-top: 0;
}

.dashboard-summary-row {
  gap: 0.7rem;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  margin-top: 0;
  padding-top: 0.75rem;
}

.dashboard-stat {
  align-content: start;
  background: rgba(248, 250, 252, 0.84);
  border: 1px solid rgba(148, 163, 184, 0.18);
  border-radius: var(--radius-2);
  gap: 0.18rem;
  min-width: 0;
  padding: 0.72rem 0.78rem;
}

.dashboard-stat strong {
  color: var(--ink-soft);
  display: block;
  font-size: var(--text-xs);
  font-weight: var(--weight-strong);
  letter-spacing: 0.12em;
  margin-bottom: 0.05rem;
  text-transform: uppercase;
}

.dashboard-stat-value {
  color: var(--accent-strong);
  font-family: var(--font-display);
  font-size: clamp(1.2rem, 2.3vw, 1.6rem);
  line-height: 1;
}

.dashboard-stat span:last-child {
  color: var(--ink-muted);
  display: none;
  font-size: 0.78rem;
  line-height: 1.4;
}

.public-side-panel,
.dashboard-side-panel,
.login-form-card {
  align-self: start;
}

.public-hero,
.note-editor-intro {
  overflow: hidden;
}

.note-editor-intro .ui-intro-block {
  gap: 0.65rem;
}

.note-editor-intro .ui-support-grid .ui-detail-block,
.note-editor-intro .ui-support-grid .detail-block {
  padding: 0.72rem 0.8rem;
}

.public-home-shell-head,
.public-home-shell-copy,
.public-home-archive,
.public-home-archive-head {
  display: grid;
  gap: var(--space-3);
}

.public-home-archive {
  gap: var(--space-4);
  padding: 1rem 1rem 1.1rem;
}

.public-home-archive-head {
  align-items: start;
  gap: 0.95rem;
  padding-bottom: 0.95rem;
  position: relative;
}

.public-home-archive-head::after {
  background: rgba(100, 116, 139, 0.12);
  bottom: 0;
  content: "";
  height: 1px;
  left: 0;
  position: absolute;
  right: 0;
}

.public-home-shell-head {
  gap: 0.85rem;
}

.public-home-shell-copy {
  gap: 0.2rem;
}

.public-home-count {
  align-items: start;
  background: rgba(247, 250, 252, 0.78);
  border: 1px solid rgba(148, 163, 184, 0.14);
  border-radius: 1.1rem;
  display: inline-grid;
  gap: 0.1rem;
  justify-self: start;
  min-width: 0;
  padding: 0.52rem 0.76rem 0.58rem;
}

.public-home-count span {
  color: var(--ink-faint);
  font-family: var(--font-ui);
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.public-home-count strong {
  color: var(--ink-soft);
  font-family: var(--font-display);
  font-size: clamp(0.92rem, 1.45vw, 1.08rem);
  font-weight: 590;
  letter-spacing: -0.02em;
  line-height: 1.12;
}

.public-intro-panel {
  gap: 0.65rem;
}

